def min_cost(cost, m, n):
    if m == 0 and n == 0:
        return cost[0][0]

    if m < 0 or n < 0:
        return float('inf')

    up = min_cost(cost, m-1, n) + cost[m][n]
    left = min_cost(cost, m, n-1) + cost[m][n]

    return min(up, left)

